// INFO ------------------------------------------------------------------------
// Module generates delayed pulse one clock width
//
// - Could be useful for initialization or sequencing some tasks
// - Could be easily daisy-chained by connecting "after_event" outputs
//   to the subsequent "ena" inputs
// - Only one event can be triggered after every reset
// - Delay operation could be suspended by setting ena to 0 at any time


//  |
//  |___,___,   ,___,___,___,___,___,___,___,___,___,___,___,
//  |   ,   |___|   ,   ,   ,   ,   ,   ,   ,   ,   ,   ,   , nrst
//  |
//  |            <---------- DELAY -------->
//  |                                        ___
//  |___,___,___,___,___,___,___,___,___,___|   |___,___,___, on_event
//  |
//  |           ,___,___,___,___,___,___,___,
//  |___,___,___|   ,   ,   ,   ,   ,   ,   |___,___,___,___, before_event
//  |
//  |___,___,___                             ___,___,___,___,
//  |   ,   ,   |___,___,___,___,___,___,___|   ,   ,   ,   , after_event
//  |
//


/* --- INSTANTIATION TEMPLATE BEGIN ---

delayed_event #(
  .DELAY( 8 )
) de1 (
  .clk( clk ),
  .nrst( nrst ),
  .ena(  ),

  .on_event(  ),        // one clock cycle
  .before_event(  ),
  .after_event(  )
);

--- INSTANTIATION TEMPLATE END ---*/

module delayed_event #( parameter
  DELAY = 32
)(
  input clk,                          // system clock
  input nrst,                         // negative reset
  input ena,                          // enable

  output on_event,                    // one clock cycle
  output before_event,                // event outputs
  output after_event                  // event outputs
);


  localparam CNTR_W = $clog2(DELAY+1);

  generate
    //==========================================================================
    if ( DELAY == 0 ) begin

      logic ena_rise;
      edge_detect event_edge (
        .clk( clk ),
        .anrst( nrst ),
        .in( ena ),
        .rising( ena_rise )
      );

      assign on_event = ena_rise;
      assign before_event = 1'b0;
      assign after_event = 1'b1;

    //==========================================================================
    end else if ( DELAY == 1 ) begin

      logic ena_d1 = 1'b0;
      always_ff @(posedge clk) begin
        if( ~nrst ) begin
          ena_d1 <= 1'b0;
        end else begin
          ena_d1 <= ena;
        end
      end

      logic ena_rise;
      edge_detect event_edge (
        .clk( clk ),
        .anrst( nrst ),
        .in( ena_d1 ),
        .rising( ena_rise )
      );

      logic got_ena = 1'b0;
      always_ff @(posedge clk) begin
        if( ~nrst ) begin
          got_ena <= 1'b0;
        end if( on_event ) begin
          got_ena <= 1'b1;
        end
      end

      assign on_event = ena_rise;
      assign before_event = !got_ena && !ena_rise;
      assign after_event = got_ena || ena_rise;

    //==========================================================================
    end else begin

      logic [CNTR_W-1:0] seq_cntr = CNTR_W'(DELAY);

      logic seq_cntr_is_0;
      assign seq_cntr_is_0 = (seq_cntr[CNTR_W-1:0]=='0);

      always_ff @(posedge clk) begin
        if( ~nrst) begin
          seq_cntr[CNTR_W-1:0] <= CNTR_W'(DELAY);
        end else begin
          if( ena && ~seq_cntr_is_0 ) begin
            seq_cntr[CNTR_W-1:0] <= seq_cntr[CNTR_W-1:0] - 1'b1;
          end
        end // nrst
      end

      edge_detect event_edge (
        .clk( clk ),
        .anrst( 1'b1 ),
        .in( seq_cntr_is_0 ),
        .rising( on_event )
      );

      assign before_event = ~seq_cntr_is_0;
      assign after_event = seq_cntr_is_0;

    end
  endgenerate

endmodule

//--------------------------------------------------------------------------------
// dynamic_delay.sv
// published as part of https://github.com/pConst/basic_verilog
// Konstantin Pavlov, pavlovconst@gmail.com
//--------------------------------------------------------------------------------

// INFO --------------------------------------------------------------------------------
//  Dynamic delay for arbitrary signal.
//
//  Incoming data elements have WIDTH bits each. Module does serialization of
//  input data and outputs flattened bits, based on provided selector value.
//  You can perform delays bit-wize, not just element-wize.
//
//  CAUTION: Be careful selecting last, most-delayed "WIDTH" number of bits.
//           The module intentionally does NOT implement "out of range"
//           checks. Please handle them externally.



/* --- INSTANTIATION TEMPLATE BEGIN ---

dynamic_delay #(
  .LENGTH( 3 ),
  .WIDTH( 4 )
) M (
  .clk( clk ),
  .nrst( nrst ),
  .ena( 1'b1 ),
  .in( in_data[3:0] ),
  .sel( sel[3:0] ),
  .out( out_data[3:0] )
);

--- INSTANTIATION TEMPLATE END ---*/


module dynamic_delay #( parameter
  LENGTH = 63,                        // maximum delay chain length
  WIDTH = 4,                          // data width

  SEL_W = $clog2( (LENGTH+1)*WIDTH )  // output selector width
                                      //  plus one is for zero delay element
)(
  input clk,
  input nrst,
  input ena,
  input [WIDTH-1:0] in,               // input data
                                      // bit in[0] is the "oldest" one
                                      // bit in[WIDTH] is considered the most recent
  input [SEL_W-1:0] sel,              // output selector
  output logic [WIDTH-1:0] out        // output data
);



logic [(LENGTH+1)-1:0][WIDTH-1:0] data = '0;

// packed vector includes extra bits
logic [(LENGTH+1)*WIDTH-1:0] pack_data;
assign pack_data[(LENGTH+1)*WIDTH-1:0] = data;

integer i;
always_ff @(posedge clk) begin
  if( ~nrst ) begin
    // reset all data except zero element
    for( i=1; i<(LENGTH+1); i=i+1 ) begin
      data[i][WIDTH-1:0] <= '0;
    end
  end else if (ena) begin
    for( i=1; i<(LENGTH+1); i=i+1 ) begin
      data[i][WIDTH-1:0] <= data[i-1][WIDTH-1:0];
    end
  end
end

integer j;
always_comb begin
  // zero element assignment
  data[0][WIDTH-1:0] <= in[WIDTH-1:0];

  // output selector, sel==0 gives non-delayed output
  for( j=0; j<WIDTH; j=j+1 ) begin
    out[j] <= pack_data[sel[SEL_W-1:0]+j];
  end
end

endmodule

